// SERVER-SIDE JavaScript String Escaping - For embedding values in inline <script> tags
function escapeJSServer(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\\\')   // Backslash
    .replace(/'/g, "\\'")     // Single quote  
    .replace(/"/g, '\\"')     // Double quote
    .replace(/\n/g, '\\n')    // Newline
    .replace(/\r/g, '\\r')    // Carriage return
    .replace(/\t/g, '\\t');   // Tab
}

// CLIENT-SIDE Escaping Utilities (embedded in HTML for browser use)
// HTML Escaping Utility - Prevents XSS and syntax errors
function escapeHTML(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// JavaScript String Escaping - For use in onclick handlers and JS strings
function escapeJS(str) {
  if (!str) return '';
  return String(str)
    .replace(/\\/g, '\\\\')   // Backslash
    .replace(/'/g, "\\'")     // Single quote
    .replace(/"/g, '\\"')     // Double quote
    .replace(/\n/g, '\\n')    // Newline
    .replace(/\r/g, '\\r')    // Carriage return
    .replace(/\t/g, '\\t');   // Tab
}

// Backend API URLs
// Server-side: Use localhost for Node.js to FastAPI calls
const BACKEND_URL_SERVER = 'http://localhost:8000';

// Browser-side: Use public HTTPS URL for browser JavaScript
const BACKEND_URL_BROWSER = process.env.BACKEND_URL || 
  (process.env.REPLIT_DOMAINS 
    ? `https://${process.env.REPLIT_DOMAINS.replace(/(\.[^.]+\.replit\.dev)$/i, '-8000$1')}`
    : 'http://localhost:8000');

// ============================================================================
// CENTRALIZED ROUTE MAP - Systematic route registration for all pages
// ============================================================================
// Feature flag: Set to false initially for safety, enable after testing
const ROUTE_MAP_ENABLED = false;

// Route map: Declarative route definitions
// Structure: { path: string, handler: string (legacy placeholder), authRequired: boolean }
const ROUTE_MAP = {};

/**
 * Normalize and resolve route from request
 * @param {http.IncomingMessage} req - HTTP request
 * @returns {object|null} - Route config or null if not found
 */
function resolveRoute(req) {
  if (!ROUTE_MAP_ENABLED) return null;
  
  // Parse URL and strip query parameters
  const urlObj = new URL(req.url, `http://${req.headers.host || 'localhost'}`);
  let pathname = urlObj.pathname;
  
  // Normalize path: ensure no trailing slash (except root)
  if (pathname.length > 1 && pathname.endsWith('/')) {
    pathname = pathname.slice(0, -1);
  }
  
  // Look up in route map
  return ROUTE_MAP[pathname] || null;
}

