                html += '<th>Date</th>';
                html += '<th>Direct Facilitation</th>';
                html += '<th>Group Performance Recognition</th>';
                html += '<th>VED Leadership Recognition</th>';
                html += '<th>Earned Mentorship Contribution Benefit</th>';
                html += '<th class="bg-primary">Gross Earning</th>';
                html += '<th class="bg-warning">Paid Mentorship Contribution Benefit</th>';
                html += '<th class="bg-danger">TDS & Admin</th>';
                html += '<th class="bg-success">Final Earning</th>';
                html += '</tr></thead><tbody>';
                
                breakdown.forEach(day => {
                  html += '<tr>';
                  html += '<td><strong>' + new Date(day.date).toLocaleDateString('en-IN') + '</strong></td>';
                  html += '<td>₹' + (day.direct_referral || 0).toLocaleString() + '</td>';
                  html += '<td>₹' + (day.matching_referral || 0).toLocaleString() + '</td>';
                  html += '<td>₹' + (day.ved_income || 0).toLocaleString() + '</td>';
                  html += '<td>₹' + (day.earned_guru_dakshina || 0).toLocaleString() + '</td>';
                  html += '<td class="fw-bold text-primary">₹' + (day.gross_earning || 0).toLocaleString() + '</td>';
                  html += '<td class="text-warning">₹' + (day.paid_guru_dakshina || 0).toLocaleString() + '</td>';
                  html += '<td class="text-danger">₹' + (day.tds_admin || 0).toLocaleString() + '</td>';
                  html += '<td class="fw-bold text-success">₹' + (day.final_earning || 0).toLocaleString() + '</td>';
                  html += '</tr>';
                });
                
                // Totals row
                html += '<tr class="table-secondary fw-bold">';
                html += '<td>TOTAL</td>';
                html += '<td>₹' + (totals.direct_referral || 0).toLocaleString() + '</td>';
                html += '<td>₹' + (totals.matching_referral || 0).toLocaleString() + '</td>';
                html += '<td>₹' + (totals.ved_income || 0).toLocaleString() + '</td>';
                html += '<td>₹' + (totals.earned_guru_dakshina || 0).toLocaleString() + '</td>';
                html += '<td class="text-primary">₹' + (totals.gross_earning || 0).toLocaleString() + '</td>';
                html += '<td class="text-warning">₹' + (totals.paid_guru_dakshina || 0).toLocaleString() + '</td>';
                html += '<td class="text-danger">₹' + (totals.tds_admin || 0).toLocaleString() + '</td>';
                html += '<td class="text-success">₹' + (totals.final_earning || 0).toLocaleString() + '</td>';
